(game "Fearless Pretty Oxpecker – Simple"
    (players 2)

    (equipment
        (board (square 8))
    )

    (rules
        (play
            (repeat (P1 P2)
                (place
                    (destination empty)
                )
            )
        )
        (end
            (if (line 4) (mover win))
            (if (full_board) (draw))
        )
    )
)

