(game "Fearless Pretty Oxpecker – Fearless Placement"
    (players 2)

    (equipment
        (board (square 8))
    )

    (rules
        (start
            (place P1 (0 0))
            (place P2 (7 7))
        )
        (play
            (repeat (P1 P2)
                (place
                    (destination
                        (and
                            empty
                            (not (adjacent (occupied mover)))   ; cannot be next to own stone
                        )
                    )
                    (effects
                        (capture (adjacent (occupied opponent)) increment_score:true)
                    )
                )
                (force_pass)
            )
        )
        (end
            (if (>= (score mover) 10) (mover win))
            (if (line 4) (mover win))
            (if (full_board) (draw))
        )
    )
)

(game "Fearless Pretty Oxpecker – Full"
    (players 2)

    (equipment
        (board (square 8))
    )

    (rules
        (start
            (place P1 (0 0))
            (place P2 (7 7))
        )
        (play
            (repeat (P1 P2)
                (place
                    (destination
                        (and
